// @ts-nocheck
/** DBA Ops panel — Replication status, scheduled maintenance, idle-in-transaction
 *  sessions (with kill), and backup verification (restore-test / integrity check).
 *  Opened from a connection's context menu as a main-panel tab. */
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import {
  RefreshCw, Play, Clock, Trash2, ShieldCheck, AlertTriangle,
  CheckCircle2, XCircle, Loader2, Activity, Database as DbIcon, Calendar,
  Layers, Table2, Send, Sparkles, ChevronDown, ChevronRight, Settings2, Zap,
} from 'lucide-react';
import { api } from '../../lib/api';
import { notify, notifyError, confirm } from '../../lib/notify';
import { sendSqlToTerminal } from '../../lib/sendSqlToTerminal';
import { findDbColumn, rowDatabaseName } from '../../lib/connection-breakdown';
import { IndexHealthView } from './IndexHealthView';
import { ExportButtons } from '../../components/ui/ExportButtons';
import { AiAnalysisButton } from '../../components/ai/AiAnalysisButton';

type Section = 'replication' | 'maintenance' | 'sessions' | 'backups' | 'indexes' | 'tables' | 'superkill';

const SECTIONS: { id: Section; label: string; icon: any }[] = [
  { id: 'replication', label: 'Replication', icon: Activity },
  { id: 'maintenance', label: 'Maintenance', icon: Calendar },
  { id: 'sessions', label: 'Idle Sessions', icon: Clock },
  { id: 'superkill', label: 'SuperKill', icon: Zap },
  { id: 'backups', label: 'Backup Verify', icon: ShieldCheck },
  { id: 'indexes', label: 'Indexes', icon: Layers },
  { id: 'tables', label: 'Tables', icon: Table2 },
];

const CRON_OPTIONS = [
  { value: '0 * * * *', label: 'Hourly' },
  { value: '0 0 * * *', label: 'Daily (00:00)' },
  { value: '0 2 * * 0', label: 'Weekly (Sun 02:00)' },
  { value: '0 0 1 * *', label: 'Monthly (1st 00:00)' },
];

function bytes(n: number | null | undefined): string {
  if (n == null) return '—';
  const u = ['B', 'KB', 'MB', 'GB', 'TB'];
  let i = 0, v = Number(n);
  while (v >= 1024 && i < u.length - 1) { v /= 1024; i++; }
  return `${v.toFixed(v >= 10 || i === 0 ? 0 : 1)} ${u[i]}`;
}

export function DbaOpsPanel({
  connectionId,
  connectionName,
  initialDatabase,
  initialSection = 'replication',
}: {
  connectionId: string;
  connectionName?: string;
  initialDatabase?: string | null;
  initialSection?: Section;
}) {
  const [section, setSection] = useState<Section>(initialSection as Section);
  const [engine, setEngine] = useState<string>('');
  const [databases, setDatabases] = useState<string[]>([]);
  const [db, setDb] = useState<string>(initialDatabase ?? '');

  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const conns = await api.connections();
        const c = (conns as any[])?.find((x) => x.id === connectionId);
        if (alive && c) setEngine(String(c.engine ?? 'mysql'));
      } catch {}
      try {
        const d = await api.databases(connectionId);
        if (alive) {
          const list = (d?.databases ?? []) as string[];
          setDatabases(list);
          if (!db && list.length) setDb(initialDatabase && list.includes(initialDatabase) ? initialDatabase : list[0]);
        }
      } catch {}
    })();
    return () => { alive = false; };
  }, [connectionId]);

  return (
    <div className="h-full flex flex-col bg-nv-panel text-nv-text min-h-0">
      <div className="flex items-center gap-2 px-3 py-1.5 border-b border-nv-border bg-nv-toolbar shrink-0">
        <Activity size={14} className="text-violet-500" />
        <span className="font-semibold text-sm">DBA Ops — {connectionName ?? connectionId.slice(0, 8)}</span>
        <span className="text-2xs text-nv-textSubtle ml-1">({engine || '…'})</span>
        <div className="ml-auto flex items-center gap-1">
          {SECTIONS.map((s) => {
            const Icon = s.icon;
            const active = section === s.id;
            return (
              <button
                key={s.id}
                onClick={() => setSection(s.id)}
                className={`flex items-center gap-1.5 px-2.5 py-1 text-2xs rounded transition-colors ${active ? 'bg-nv-accent text-white' : 'text-nv-textSubtle hover:bg-nv-hover'}`}
              >
                <Icon size={12} className={active ? 'text-white' : 'text-nv-textMuted'} />
                {s.label}
              </button>
            );
          })}
        </div>
      </div>
      <div className="flex-1 overflow-auto p-3 min-h-0">
        {section === 'replication' && <ReplicationSection connectionId={connectionId} />}
        {section === 'maintenance' && (
          <MaintenanceSection connectionId={connectionId} engine={engine} databases={databases} db={db} setDb={setDb} />
        )}
        {section === 'sessions' && <SessionsSection connectionId={connectionId} />}
        {section === 'superkill' && (
          <SuperKillSection connectionId={connectionId} databases={databases} db={db} setDb={setDb} />
        )}
        {section === 'backups' && (
          <BackupsSection connectionId={connectionId} databases={databases} db={db} setDb={setDb} />
        )}
        {section === 'indexes' && (
          <IndexesSection connectionId={connectionId} databases={databases} db={db} setDb={setDb} />
        )}
        {section === 'tables' && (
          <TablesSection connectionId={connectionId} engine={engine} databases={databases} db={db} setDb={setDb} />
        )}
      </div>
    </div>
  );
}

/* ───────────────────────── Replication ───────────────────────── */

function ReplicationSection({ connectionId }: { connectionId: string }) {
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const check = useCallback(async () => {
    setLoading(true);
    try {
      const r = await api.replicationStatus(connectionId);
      setData(r);
    } catch (e) {
      notifyError(e, 'Replication');
    } finally {
      setLoading(false);
    }
  }, [connectionId]);

  useEffect(() => { check(); }, [check]);

  const avail = data?.available !== false;

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-2">
        <button className="nv-btn text-xs" onClick={check} disabled={loading}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <RefreshCw size={12} className="inline mr-1" />}
          Refresh
        </button>
        <ExportButtons rows={data?.replicas ?? []} filenamePrefix={`replicas-${connectionId}`} />
        {!avail && <span className="text-2xs text-nv-textSubtle">Not supported for this engine / not a replica.</span>}
      </div>

      {avail && data?.isReplica === false && !data?.replicas?.length && (
        <Callout tone="info">This instance is a standalone source (no replicas connected, not itself a replica).</Callout>
      )}

      {avail && data?.isReplica && (
        <Card title="Self as replica">
          <KV label="Engine" value={data.engine} />
          <KV label="Running" value={data.running ? 'yes' : 'no'} ok={data.running} />
          <KV label="IO thread" value={data.ioRunning ? 'running' : 'stopped'} ok={data.ioRunning} />
          <KV label="SQL thread" value={data.sqlRunning ? 'running' : 'stopped'} ok={data.sqlRunning} />
          <KV label="Seconds behind" value={data.secondsBehind == null ? '—' : `${data.secondsBehind}s`} />
          <KV label="Source host" value={data.masterHost || '—'} />
          {data.lastError && <KV label="Last error" value={data.lastError} ok={false} />}
        </Card>
      )}

      {avail && data?.replica && (
        <Card title="Self as replica (PostgreSQL)">
          <KV label="Status" value={data.replica.status} ok={/streaming/i.test(data.replica.status)} />
          <KV label="Sender host" value={data.replica.senderHost || '—'} />
          <KV label="Received LSN" value={data.replica.receivedLsn || '—'} />
          <KV label="Replay LSN" value={data.replica.replayLsn || '—'} />
          <KV label="Replay lag (bytes)" value={data.replica.lagBytes == null ? '—' : bytes(data.replica.lagBytes)} />
        </Card>
      )}

      {avail && data?.replicas?.length > 0 && (
        <Card title={`Connected replicas (${data.replicas.length})`}>
          <div className="overflow-auto">
            <table className="w-full text-2xs">
              <thead className="text-nv-textSubtle">
                <tr>
                  <th className="text-left py-1 pr-3">Application</th>
                  <th className="text-left py-1 pr-3">Client</th>
                  <th className="text-left py-1 pr-3">State</th>
                  <th className="text-left py-1 pr-3">Sync</th>
                  <th className="text-right py-1">Lag</th>
                </tr>
              </thead>
              <tbody>
                {data.replicas.map((r: any, i: number) => (
                  <tr key={i} className="border-t border-nv-border">
                    <td className="py-1 pr-3 font-mono">{r.applicationName || '—'}</td>
                    <td className="py-1 pr-3 font-mono">{r.clientAddr || '—'}</td>
                    <td className="py-1 pr-3">{r.state}</td>
                    <td className="py-1 pr-3">{r.syncState}</td>
                    <td className="py-1 text-right">{bytes(r.lagBytes)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  );
}

/* ───────────────────────── Maintenance (unified) ─────────────────────────
 * Recommendations drive maintenance: analyzing the schema produces a list of
 * DBA Ops jobs (defragmentation / VACUUM, unused & duplicate indexes, missing
 * PK) that can be run or scheduled in bulk. A collapsible custom form covers
 * ad-hoc maintenance. */
function MaintenanceSection({
  connectionId, engine, databases, db, setDb,
}: {
  connectionId: string; engine: string; databases: string[]; db: string; setDb: (s: string) => void;
}) {
  const isPg = engine === 'postgres';
  const opChoices = isPg
    ? [{ id: 'analyze', label: 'ANALYZE' }, { id: 'vacuum', label: 'VACUUM' }, { id: 'reindex', label: 'REINDEX' }]
    : [{ id: 'analyze', label: 'ANALYZE TABLE' }, { id: 'optimize', label: 'OPTIMIZE TABLE' }, { id: 'check', label: 'CHECK TABLE' }];

  // Recommendation analysis state.
  const [recs, setRecs] = useState<any[] | null>(null);
  const [summary, setSummary] = useState<any>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [selected, setSelected] = useState<Record<number, boolean>>({});
  const [running, setRunning] = useState(false);
  const [scheduling, setScheduling] = useState(false);
  const [log, setLog] = useState('');

  // Custom maintenance form state.
  const [showCustom, setShowCustom] = useState(false);
  const [ops, setOps] = useState<string[]>(['analyze']);
  const [tablesText, setTablesText] = useState('');
  const [cron, setCron] = useState(CRON_OPTIONS[1].value);
  const [schedTitle, setSchedTitle] = useState('');

  const append = (s: string) => setLog((p) => (p ? `${p}\n${s}` : s));

  const analyze = useCallback(async () => {
    if (!db) { notifyError('Select a database.', 'Maintenance'); return; }
    setAnalyzing(true);
    setLog('');
    try {
      const r = await api.schemaRecommendations(connectionId, db);
      const list: any[] = r?.recommendations ?? [];
      setRecs(list);
      setSummary(r?.summary ?? null);
      // Pre-select actionable recs (fragmentation + duplicate/unused indexes).
      const pre: Record<number, boolean> = {};
      list.forEach((rec, i) => { pre[i] = rec.op === 'optimize' || rec.op === 'vacuum' || rec.op === 'drop_index'; });
      setSelected(pre);
      if (!list.length) notify('Schema analyzed — no issues detected.', 'Maintenance');
    } catch (e) {
      notifyError(e, 'Maintenance');
    } finally {
      setAnalyzing(false);
    }
  }, [connectionId, db]);

  const toggleSel = (i: number) => setSelected((p) => ({ ...p, [i]: !p[i] }));
  const selectedRecs = () => (recs ?? []).filter((_, i) => selected[i]);

  // Run a single recommendation.
  const runOne = async (rec: any) => {
    if (rec.op === 'optimize' || rec.op === 'vacuum') {
      setRunning(true);
      append(`Running ${rec.op} on ${rec.table}…`);
      try {
        await api.maintenanceRun(
          connectionId,
          { database: db, ops: [rec.op], tables: [rec.table] },
          (ev: any) => {
            if (ev.type === 'log') append(ev.message);
            else if (ev.type === 'row') append(`[${ev.op}] ${ev.table}: ${ev.ok ? 'ok' : 'FAIL'} — ${ev.message}`);
            else if (ev.type === 'done') append(`Done — ok: ${ev.ok ?? ''}, failed: ${ev.failed ?? ''}`);
            else if (ev.type === 'error') append(`ERROR: ${ev.message}`);
          },
        );
        notify(`${rec.op} finished for ${rec.table}.`, 'Maintenance');
      } catch (e) {
        append(`ERROR: ${(e as Error).message}`);
        notifyError(e, 'Maintenance');
      } finally {
        setRunning(false);
      }
      return;
    }
    if (rec.op === 'drop_index' && rec.sql) {
      const ok = await confirm(`Run destructive DDL?\n\n${rec.sql}`, 'Drop index');
      if (!ok) return;
      sendSqlToTerminal({ connectionId, database: db, sql: rec.sql, autoRun: true, notifyMessage: 'DROP INDEX enviado al Terminal' });
      return;
    }
    if (rec.sql) sendSqlToTerminal({ connectionId, database: db, sql: rec.sql });
    else notify('Review required — no automatic SQL available.', 'Maintenance');
  };

  // Run all selected recommendations.
  const runSelected = async () => {
    const sel = selectedRecs();
    if (!sel.length) { notifyError('Select at least one recommendation.', 'Maintenance'); return; }
    const maint = sel.filter((r) => r.op === 'optimize' || r.op === 'vacuum');
    const drops = sel.filter((r) => r.op === 'drop_index' && r.sql);
    const reviews = sel.filter((r) => r.op === 'review');
    if (reviews.length) notify(`${reviews.length} review-only item(s) skipped.`, 'Maintenance');

    setRunning(true);
    setLog(`Running ${maint.length} maintenance job(s) + ${drops.length} DROP(s)…`);
    try {
      if (maint.length) {
        // Group tables by op so we issue one maintenanceRun per op.
        const byOp: Record<string, string[]> = {};
        maint.forEach((r) => { (byOp[r.op] ??= []).push(r.table); });
        for (const op of Object.keys(byOp)) {
          append(`[${op}] tables: ${byOp[op].join(', ')}`);
          await api.maintenanceRun(
            connectionId,
            { database: db, ops: [op], tables: byOp[op] },
            (ev: any) => {
              if (ev.type === 'row') append(`[${ev.op}] ${ev.table}: ${ev.ok ? 'ok' : 'FAIL'} — ${ev.message}`);
              else if (ev.type === 'done') append(`Done — ok: ${ev.ok ?? ''}, failed: ${ev.failed ?? ''}`);
              else if (ev.type === 'error') append(`ERROR: ${ev.message}`);
            },
          );
        }
      }
      for (const d of drops) {
        append(`DROP → terminal: ${d.title}`);
        sendSqlToTerminal({ connectionId, database: db, sql: d.sql, autoRun: true, notifyMessage: false });
      }
      notify(`Run finished — ${maint.length} maintenance, ${drops.length} DROP(s) sent to terminal.`, 'Maintenance');
    } catch (e) {
      append(`ERROR: ${(e as Error).message}`);
      notifyError(e, 'Maintenance');
    } finally {
      setRunning(false);
    }
  };

  // Schedule selected (only maintenance ops are schedulable via the job runner).
  const scheduleSelected = async () => {
    const maint = selectedRecs().filter((r) => r.op === 'optimize' || r.op === 'vacuum');
    if (!maint.length) { notifyError('No schedulable maintenance jobs selected (only OPTIMIZE/VACUUM).', 'Maintenance'); return; }
    const byOp: Record<string, string[]> = {};
    maint.forEach((r) => { (byOp[r.op] ??= []).push(r.table); });
    const opsList = Object.keys(byOp);
    const allTables = Array.from(new Set(opsList.flatMap((op) => byOp[op])));
    setScheduling(true);
    try {
      const job = await api.maintenanceSchedule(connectionId, {
        database: db,
        ops: opsList,
        tables: allTables,
        cronExpr: cron,
        title: schedTitle || `Recommended maintenance — ${db}`,
      });
      notify(`Scheduled maintenance job created.`, 'Maintenance');
      append(`Scheduled: ${job?.title ?? '(untitled)'} — ${cron} — ops: ${opsList.join(', ')}, tables: ${allTables.length}`);
    } catch (e) {
      notifyError(e, 'Maintenance');
    } finally {
      setScheduling(false);
    }
  };

  const toggleOp = (o: string) => setOps((p) => (p.includes(o) ? p.filter((x) => x !== o) : [...p, o]));

  // Custom ad-hoc run.
  const runCustom = async () => {
    if (!db) { notifyError('Select a database.', 'Maintenance'); return; }
    if (!ops.length) { notifyError('Select at least one op.', 'Maintenance'); return; }
    setRunning(true);
    setLog(`Starting maintenance on ${db}… (${new Date().toISOString()})`);
    const tables = tablesText.trim() ? tablesText.split(/[,\s]+/).filter(Boolean) : null;
    try {
      await api.maintenanceRun(connectionId, { database: db, ops, tables }, (ev: any) => {
        if (ev.type === 'log') append(ev.message);
        else if (ev.type === 'row') append(`[${ev.op}] ${ev.table}: ${ev.ok ? 'ok' : 'FAIL'} — ${ev.message}`);
        else if (ev.type === 'done') append(`Done — ok: ${ev.ok ?? ''}, failed: ${ev.failed ?? ''}`);
        else if (ev.type === 'error') append(`ERROR: ${ev.message}`);
      });
      notify('Maintenance finished.', 'Maintenance');
    } catch (e) {
      append(`ERROR: ${(e as Error).message}`);
      notifyError(e, 'Maintenance');
    } finally {
      setRunning(false);
    }
  };

  const selCount = selectedRecs().length;
  const selMaintCount = selectedRecs().filter((r) => r.op === 'optimize' || r.op === 'vacuum').length;

  return (
    <div className="space-y-3">
      {/* Header: analyze + db selector */}
      <div className="flex items-end gap-2 flex-wrap">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Database</span>
          <select className="nv-select" value={db} onChange={(e) => { setDb(e.target.value); setRecs(null); setSummary(null); }}>
            <option value="">—</option>
            {databases.map((d) => <option key={d} value={d}>{d}</option>)}
          </select>
        </label>
        <button className="nv-btn-primary text-xs" onClick={analyze} disabled={analyzing || !db}>
          {analyzing ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <Sparkles size={12} className="inline mr-1" />}
          Analyze schema
        </button>
        {recs && (
          <button className="nv-btn text-xs" onClick={() => { setRecs(null); setSummary(null); setSelected({}); }} title="Clear analysis">
            <RefreshCw size={12} className="inline mr-1" /> Clear
          </button>
        )}
      </div>

      <Callout tone="info">
        <strong>Recommendations → Maintenance.</strong> Analyze the schema to surface DBA Ops jobs
        (table defragmentation via {isPg ? 'VACUUM' : 'OPTIMIZE'}, unused / duplicate indexes via DROP, missing primary keys).
        Select items and run or schedule them in bulk. Advisory only — review before running.
      </Callout>

      {/* Summary + recommendations list */}
      {recs && (
        <>
          {summary && (
            <div className="flex gap-2 flex-wrap">
              {Object.entries(summary).map(([k, v]) => (
                <SummaryPill key={k} label={k.replace(/_/g, ' ')} value={String(v)} tone={(v as number) > 0 ? 'warn' : 'ok'} />
              ))}
            </div>
          )}

          {recs.length === 0 ? (
            <Callout tone="info"><CheckCircle2 size={13} className="inline mr-1" /> No issues detected — schema looks healthy.</Callout>
          ) : (
            <>
              {/* Bulk action bar */}
              <div className="flex items-center gap-2 flex-wrap border border-nv-border rounded bg-nv-toolbar/40 px-2 py-1.5">
                <span className="text-2xs text-nv-textSubtle">{selCount} selected</span>
                <button className="nv-btn-primary text-2xs" onClick={runSelected} disabled={running || selCount === 0}>
                  {running ? <Loader2 size={11} className="animate-spin inline mr-1" /> : <Play size={11} className="inline mr-1" />}
                  Run selected
                </button>
                <div className="flex items-center gap-1">
                  <select className="nv-select text-2xs" value={cron} onChange={(e) => setCron(e.target.value)} title="Cron schedule">
                    {CRON_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
                  </select>
                  <button className="nv-btn text-2xs" onClick={scheduleSelected} disabled={scheduling || selMaintCount === 0} title={selMaintCount === 0 ? 'Select OPTIMIZE/VACUUM items to schedule' : 'Schedule selected maintenance'}>
                    {scheduling ? <Loader2 size={11} className="animate-spin inline mr-1" /> : <Clock size={11} className="inline mr-1" />}
                    Schedule ({selMaintCount})
                  </button>
                </div>
                <button className="nv-btn text-2xs ml-auto" onClick={() => setSelected((p) => { const n: Record<number, boolean> = {}; recs.forEach((_, i) => { n[i] = !Object.values(p).some(Boolean); }); return n; })} title="Toggle all">
                  Toggle all
                </button>
              </div>

              <div className="space-y-2">
                {recs.map((rec, i) => (
                  <div key={i} className={`border rounded bg-nv-toolbar/30 p-2 ${selected[i] ? 'border-nv-accent/50' : 'border-nv-border'}`}>
                    <div className="flex items-center gap-2">
                      <input type="checkbox" checked={!!selected[i]} onChange={() => toggleSel(i)} />
                      <Pill tone={rec.severity === 'high' ? 'err' : rec.severity === 'medium' ? 'warn' : 'muted'}>{rec.severity}</Pill>
                      <Pill tone="muted">{rec.category.replace(/_/g, ' ')}</Pill>
                      <span className="font-mono text-2xs text-nv-text flex-1 min-w-0 truncate" title={rec.title}>{rec.title}</span>
                      <button
                        className="nv-btn text-2xs"
                        onClick={() => runOne(rec)}
                        disabled={running}
                        title={rec.op === 'review' ? 'Review' : rec.op === 'drop_index' ? 'Send DROP to terminal' : `Run ${rec.op}`}
                      >
                        {rec.op === 'review' ? <AlertTriangle size={11} className="inline" /> : rec.op === 'drop_index' ? <Send size={11} className="inline" /> : <Play size={11} className="inline" />}
                        <span className="ml-1">{rec.op === 'review' ? 'Review' : rec.op === 'drop_index' ? 'Terminal' : 'Run'}</span>
                      </button>
                    </div>
                    <div className="text-2xs text-nv-textSubtle mt-1">{rec.detail}</div>
                    {rec.sql && (
                      <pre className="mt-1 text-2xs font-mono bg-nv-bg border border-nv-border rounded p-1.5 overflow-auto text-nv-text">{rec.sql}</pre>
                    )}
                  </div>
                ))}
              </div>
            </>
          )}
        </>
      )}

      {!recs && !analyzing && (
        <p className="text-2xs text-nv-textMuted">Run <strong>Analyze schema</strong> to surface recommended DBA Ops jobs, or expand <strong>Custom maintenance</strong> below for ad-hoc ops.</p>
      )}

      {/* Progress log */}
      {log && (
        <div>
          <div className="text-2xs text-nv-textSubtle mb-0.5">Progress</div>
          <textarea readOnly className="w-full h-28 nv-input font-mono text-2xs bg-nv-bg" value={log} placeholder="Events from server…" />
        </div>
      )}

      {/* Custom ad-hoc maintenance (collapsible) */}
      <div className="border-t border-nv-border pt-2">
        <button
          type="button"
          onClick={() => setShowCustom((v) => !v)}
          className="w-full flex items-center gap-1.5 text-xs text-nv-textSubtle hover:text-nv-text py-1"
        >
          {showCustom ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
          <Settings2 size={12} className="text-nv-accent" />
          <span className="font-semibold">Custom maintenance</span>
          <span className="text-2xs opacity-70">· ad-hoc ops on selected tables</span>
        </button>
        {showCustom && (
          <div className="mt-2 space-y-2.5">
            <div className="flex items-end gap-3 flex-wrap">
              <div className="text-xs">
                <span className="text-2xs text-nv-textSubtle block mb-0.5">Operations</span>
                <div className="flex gap-2 flex-wrap">
                  {opChoices.map((o) => (
                    <label key={o.id} className="flex items-center gap-1 cursor-pointer">
                      <input type="checkbox" checked={ops.includes(o.id)} onChange={() => toggleOp(o.id)} disabled={running} />
                      <span className="font-mono text-2xs">{o.label}</span>
                    </label>
                  ))}
                </div>
              </div>
            </div>
            <label className="block text-xs">
              <span className="text-2xs text-nv-textSubtle block mb-0.5">Tables (optional, blank = all tables; comma or space separated)</span>
              <input className="nv-input w-full font-mono text-2xs" value={tablesText} onChange={(e) => setTablesText(e.target.value)} placeholder="users, orders, products" disabled={running} />
            </label>
            <div className="flex items-center gap-2">
              <button className="nv-btn-primary text-xs" onClick={runCustom} disabled={running || !db}>
                {running ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <Play size={12} className="inline mr-1" />}
                Run now
              </button>
              <input className="nv-input flex-1 text-2xs" value={schedTitle} onChange={(e) => setSchedTitle(e.target.value)} placeholder={`Maintenance ${db}`} disabled={running} />
              <button className="nv-btn text-xs" onClick={async () => {
                if (!db || !ops.length) { notifyError('Select a database and at least one op.', 'Maintenance'); return; }
                try {
                  const tables = tablesText.trim() ? tablesText.split(/[,\s]+/).filter(Boolean) : null;
                  const job = await api.maintenanceSchedule(connectionId, { database: db, ops, tables, cronExpr: cron, title: schedTitle || undefined });
                  notify('Scheduled maintenance job created.', 'Maintenance');
                  append(`Scheduled: ${job?.title ?? '(untitled)'} — ${cron}`);
                } catch (e) { notifyError(e, 'Maintenance'); }
              }}><Clock size={12} className="inline mr-1" /> Schedule</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* ───────────────────────── Idle sessions ───────────────────────── */

function SessionsSection({ connectionId }: { connectionId: string }) {
  const [minSec, setMinSec] = useState(60);
  const [sessions, setSessions] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [available, setAvailable] = useState(true);

  const list = useCallback(async () => {
    setLoading(true);
    try {
      const r = await api.idleSessions(connectionId, minSec);
      setSessions(r?.sessions ?? []);
      setAvailable(r?.available !== false);
    } catch (e) {
      notifyError(e, 'Idle Sessions');
    } finally {
      setLoading(false);
    }
  }, [connectionId, minSec]);

  useEffect(() => { list(); }, [list]);

  const kill = async (pid: number) => {
    const ok = await confirm(`Kill session ${pid}? This terminates the transaction.`, 'Kill session');
    if (!ok) return;
    try {
      await api.killSession(connectionId, pid);
      notify(`Killed session ${pid}.`, 'Idle Sessions');
      setSessions((p) => p.filter((s) => s.pid !== pid));
    } catch (e) {
      notifyError(e, 'Idle Sessions');
    }
  };

  return (
    <div className="space-y-3">
      <div className="flex items-end gap-2">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Idle ≥ (seconds)</span>
          <input type="number" min={1} className="nv-input w-24 text-2xs" value={minSec} onChange={(e) => setMinSec(Math.max(1, Number(e.target.value)))} />
        </label>
        <button className="nv-btn text-xs" onClick={list} disabled={loading}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <RefreshCw size={12} className="inline mr-1" />}
          List
        </button>
        <ExportButtons rows={sessions} filenamePrefix={`idle-sessions-${connectionId}`} />
      </div>
      {!available && <Callout tone="info">Not supported for this engine.</Callout>}
      {available && (
        <Callout tone="info">
          Auto-kill policy: configure it in <strong>Settings → Alerts → “Idle in transaction”</strong> (enable the rule and set the <code>autoKill</code> param). Manual kill is available per row below.
        </Callout>
      )}
      {available && sessions.length > 0 && (
        <div className="border border-nv-border rounded overflow-auto">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle">
              <tr>
                <th className="text-left px-2 py-1">PID</th>
                <th className="text-left px-2 py-1">User</th>
                <th className="text-left px-2 py-1">DB</th>
                <th className="text-right px-2 py-1">Idle</th>
                <th className="text-left px-2 py-1">State</th>
                <th className="text-left px-2 py-1">Query</th>
                <th className="px-2 py-1" />
              </tr>
            </thead>
            <tbody>
              {sessions.map((s) => (
                <tr key={s.pid} className="border-t border-nv-border">
                  <td className="px-2 py-1 font-mono">{s.pid}</td>
                  <td className="px-2 py-1">{s.user}</td>
                  <td className="px-2 py-1">{s.database}</td>
                  <td className="px-2 py-1 text-right">{s.timeSec}s</td>
                  <td className="px-2 py-1">{s.state}</td>
                  <td className="px-2 py-1 font-mono max-w-[280px] truncate" title={s.query}>{s.query}</td>
                  <td className="px-2 py-1 text-right">
                    <button className="nv-btn text-2xs" onClick={() => kill(s.pid)} title="Kill session">
                      <Trash2 size={11} className="inline" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      {available && sessions.length === 0 && !loading && (
        <p className="text-2xs text-nv-textMuted">No idle-in-transaction sessions ≥ {minSec}s.</p>
      )}
    </div>
  );
}

/* ───────────────────────── SuperKill ─────────────────────────
 * Kill every active connection to the selected database, protecting
 * this panel's own session from self-termination (handled server-side). */

function SuperKillSection({
  connectionId, databases, db, setDb,
}: {
  connectionId: string; databases: string[]; db: string; setDb: (s: string) => void;
}) {
  const [rows, setRows] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [killing, setKilling] = useState(false);
  const [result, setResult] = useState<any>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const r = await api.processlist(connectionId);
      setRows(Array.isArray(r) ? r : []);
    } catch (e) {
      notifyError(e, 'SuperKill');
    } finally {
      setLoading(false);
    }
  }, [connectionId]);

  useEffect(() => { refresh(); }, [refresh]);

  const matching = useMemo(() => {
    if (!db) return [];
    return rows.filter((r) => {
      const col = findDbColumn([r]);
      const name = rowDatabaseName(r, col);
      return name !== '(sin DB)' && name.toLowerCase() === db.toLowerCase();
    });
  }, [rows, db]);

  const pidOf = (r: any): string => String(r.Id ?? r.id ?? r.pid ?? r.PID ?? r.thread_id ?? '');

  const doKill = async () => {
    if (!db) { notifyError('Select a database first.', 'SuperKill'); return; }
    const ok = await confirm(
      `SuperKill all ${matching.length} connection(s) to "${db}"?\n\nThis terminates every session using that database. The kill list is resolved server-side and your own session is protected.`,
      'SuperKill',
    );
    if (!ok) return;
    setKilling(true);
    setResult(null);
    try {
      const r = await api.superKill(connectionId, db);
      setResult(r);
      notify(
        `SuperKill done — killed: ${r?.killed ?? 0}, failed: ${r?.failed ?? 0}, skipped: ${r?.skipped ?? 0}.`,
        'SuperKill',
      );
      refresh();
    } catch (e) {
      notifyError(e, 'SuperKill');
    } finally {
      setKilling(false);
    }
  };

  return (
    <div className="space-y-3">
      <div className="flex items-end gap-2 flex-wrap">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Target database</span>
          <select className="nv-select" value={db} onChange={(e) => { setDb(e.target.value); setResult(null); }}>
            <option value="">—</option>
            {databases.map((d) => <option key={d} value={d}>{d}</option>)}
          </select>
        </label>
        <button className="nv-btn text-xs" onClick={refresh} disabled={loading}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <RefreshCw size={12} className="inline mr-1" />}
          List connections
        </button>
        <button
          className="nv-btn text-xs border-nv-danger/50 text-nv-danger hover:bg-nv-danger/10"
          onClick={doKill}
          disabled={killing || !db}
          title="Kill all connections to the selected database"
        >
          {killing ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <Zap size={12} className="inline mr-1" />}
          SuperKill
        </button>
        {db && (
          <span className="text-2xs text-nv-textSubtle ml-1">
            {matching.length} connection(s) match <span className="font-mono text-nv-text">{db}</span>
          </span>
        )}
      </div>

      <Callout tone="warn">
        <strong>SuperKill</strong> terminates <em>every</em> active session whose current database is the
        selected one. Use with care on production instances — long-running queries and idle connections alike
        are killed. Your own DB Tool Box session is excluded automatically.
      </Callout>

      {!db && <p className="text-2xs text-nv-textMuted">Select a database to list its connections.</p>}

      {db && matching.length === 0 && !loading && (
        <Callout tone="info"><CheckCircle2 size={13} className="inline mr-1" /> No active connections to <span className="font-mono">{db}</span> right now.</Callout>
      )}

      {db && matching.length > 0 && (
        <div className="border border-nv-border rounded overflow-auto">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle">
              <tr>
                <th className="text-left px-2 py-1">PID</th>
                <th className="text-left px-2 py-1">User</th>
                <th className="text-left px-2 py-1">Host</th>
                <th className="text-left px-2 py-1">State</th>
                <th className="text-left px-2 py-1">Query</th>
              </tr>
            </thead>
            <tbody>
              {matching.map((r, i) => (
                <tr key={i} className="border-t border-nv-border">
                  <td className="px-2 py-1 font-mono">{pidOf(r)}</td>
                  <td className="px-2 py-1">{String(r.User ?? r.usename ?? r.user ?? '—')}</td>
                  <td className="px-2 py-1 font-mono">{String(r.Host ?? r.client_addr ?? r.application_name ?? r.host ?? '—')}</td>
                  <td className="px-2 py-1">{String(r.State ?? r.state ?? r.Command ?? r.command ?? '—')}</td>
                  <td className="px-2 py-1 font-mono max-w-[320px] truncate" title={String(r.Info ?? r.query ?? '')}>{String(r.Info ?? r.query ?? '')}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {result && (
        <div className="border border-nv-border rounded bg-nv-toolbar/30 p-2 space-y-2">
          <div className="flex gap-2 flex-wrap">
            <SummaryPill label="Killed" value={result.killed ?? 0} tone={(result.killed ?? 0) > 0 ? 'ok' : 'muted'} />
            <SummaryPill label="Failed" value={result.failed ?? 0} tone={(result.failed ?? 0) > 0 ? 'warn' : 'ok'} />
            <SummaryPill label="Skipped (self)" value={result.skipped ?? 0} />
            <SummaryPill label="Database" value={result.database ?? db} />
          </div>
          {result.available === false && (
            <Callout tone="warn">{String(result.message ?? 'Not supported for this engine.')}</Callout>
          )}
          {Array.isArray(result.results) && result.results.length > 0 && (
            <div className="border border-nv-border rounded overflow-auto">
              <table className="w-full text-2xs">
                <thead className="bg-nv-gridHeader text-nv-textSubtle">
                  <tr>
                    <th className="text-left px-2 py-1">PID</th>
                    <th className="text-left px-2 py-1">User</th>
                    <th className="text-left px-2 py-1">Host</th>
                    <th className="text-left px-2 py-1">State</th>
                    <th className="text-left px-2 py-1">Result</th>
                  </tr>
                </thead>
                <tbody>
                  {result.results.map((r: any, i: number) => (
                    <tr key={i} className="border-t border-nv-border">
                      <td className="px-2 py-1 font-mono">{r.pid}</td>
                      <td className="px-2 py-1">{r.user || '—'}</td>
                      <td className="px-2 py-1 font-mono">{r.host || '—'}</td>
                      <td className="px-2 py-1">{r.state || '—'}</td>
                      <td className="px-2 py-1">
                        {r.ok
                          ? <Pill tone="ok"><CheckCircle2 size={10} className="inline mr-1" />killed</Pill>
                          : <Pill tone="err"><XCircle size={10} className="inline mr-1" />{r.error || 'failed'}</Pill>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ───────────────────────── Backup verify ───────────────────────── */

function BackupsSection({
  connectionId, databases, db, setDb,
}: {
  connectionId: string; databases: string[]; db: string; setDb: (s: string) => void;
}) {
  const [rows, setRows] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [verifying, setVerifying] = useState<string | null>(null);
  const [log, setLog] = useState('');

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const r = await api.backupList(connectionId, db || undefined);
      setRows(Array.isArray(r) ? r : []);
    } catch (e) {
      notifyError(e, 'Backup Verify');
    } finally {
      setLoading(false);
    }
  }, [connectionId, db]);

  useEffect(() => { refresh(); }, [refresh]);

  const append = (s: string) => setLog((p) => (p ? `${p}\n${s}` : s));

  const verify = async (b: any) => {
    setVerifying(b.id);
    setLog(`Verifying backup ${b.id} (${b.format})…`);
    try {
      await api.backupVerify(connectionId, b.id, (ev: any) => {
        if (ev.type === 'log') append(ev.message);
        else if (ev.type === 'done') append(`Done — status: ${ev.status}`);
        else if (ev.type === 'error') append(`ERROR: ${ev.message}`);
      });
      notify('Verification finished.', 'Backup Verify');
      refresh();
    } catch (e) {
      append(`ERROR: ${(e as Error).message}`);
      notifyError(e, 'Backup Verify');
    } finally {
      setVerifying(null);
    }
  };

  const statusTone = (s: string | null) =>
    s === 'ok' || s === 'integrity_ok' ? 'ok' : s === 'mismatch' ? 'warn' : s === 'error' ? 'err' : 'muted';

  return (
    <div className="space-y-3">
      <div className="flex items-end gap-2">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Database (filter)</span>
          <select className="nv-select" value={db} onChange={(e) => setDb(e.target.value)}>
            <option value="">All</option>
            {databases.map((d) => <option key={d} value={d}>{d}</option>)}
          </select>
        </label>
        <button className="nv-btn text-xs" onClick={refresh} disabled={loading}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <RefreshCw size={12} className="inline mr-1" />}
          Refresh
        </button>
        <ExportButtons rows={rows} filenamePrefix={`backups-${connectionId}`} />
      </div>
      <Callout tone="info">
        <strong>Restore-test</strong> (dbtb2 &amp; PostgreSQL native): restores into a throwaway scratch DB and compares per-table row counts.
        <strong> MySQL native / Mongo</strong>: read-only integrity check (SHA-256 + structural completeness) — isolated restore is unsafe for db-qualified dumps.
      </Callout>
      {rows.length === 0 && !loading && <p className="text-2xs text-nv-textMuted">No backups.</p>}
      {rows.length > 0 && (
        <div className="border border-nv-border rounded overflow-auto">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle">
              <tr>
                <th className="text-left px-2 py-1">Started</th>
                <th className="text-left px-2 py-1">Database</th>
                <th className="text-left px-2 py-1">Format</th>
                <th className="text-right px-2 py-1">Size</th>
                <th className="text-left px-2 py-1">Status</th>
                <th className="text-left px-2 py-1">Verify</th>
                <th className="px-2 py-1" />
              </tr>
            </thead>
            <tbody>
              {rows.map((b) => (
                <tr key={b.id} className="border-t border-nv-border">
                  <td className="px-2 py-1">{String(b.startedAt ?? '').slice(0, 19)}</td>
                  <td className="px-2 py-1">{b.database}</td>
                  <td className="px-2 py-1 font-mono">{b.format}</td>
                  <td className="px-2 py-1 text-right">{bytes(Number(b.sizeBytes))}</td>
                  <td className="px-2 py-1">{b.status}</td>
                  <td className="px-2 py-1"><Pill tone={statusTone(b.verifyStatus)}>{b.verifyStatus ?? '—'}</Pill></td>
                  <td className="px-2 py-1 text-right">
                    <button
                      className="nv-btn text-2xs"
                      onClick={() => verify(b)}
                      disabled={verifying === b.id}
                      title="Verify backup"
                    >
                      {verifying === b.id ? <Loader2 size={11} className="animate-spin inline" /> : <ShieldCheck size={11} className="inline" />}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <div>
        <div className="text-2xs text-nv-textSubtle mb-0.5">Verify log</div>
        <textarea readOnly className="w-full h-32 nv-input font-mono text-2xs bg-nv-bg" value={log} placeholder="Verification events…" />
      </div>
    </div>
  );
}

