/* ───────────────────────── Table defragmentation ───────────────────────── */

function TablesSection({
  connectionId, engine, databases, db, setDb,
}: {
  connectionId: string; engine: string; databases: string[]; db: string; setDb: (s: string) => void;
}) {
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [optimizing, setOptimizing] = useState(false);
  const [log, setLog] = useState('');

  const isPg = engine === 'postgres';

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const r = await api.tableFragmentation(connectionId, db || undefined);
      setData(r);
    } catch (e) {
      notifyError(e, 'Tables');
    } finally {
      setLoading(false);
    }
  }, [connectionId, db]);

  useEffect(() => { if (db) refresh(); }, [refresh]);

  const append = (s: string) => setLog((p) => (p ? `${p}\n${s}` : s));

  const optimizeFragmented = async () => {
    const frag = (data?.tables ?? []).filter((t: any) => t.fragmented);
    if (!frag.length) { notify('No fragmented tables to optimize.'); return; }
    const op = isPg ? 'vacuum' : 'optimize';
    const ok = await confirm(
      `${isPg ? 'VACUUM (ANALYZE)' : 'OPTIMIZE TABLE'} on ${frag.length} fragmented table(s) in ${db}?`,
      'Defragment tables',
    );
    if (!ok) return;
    setOptimizing(true);
    setLog(`Starting ${op} on ${frag.length} fragmented tables in ${db}…`);
    try {
      await api.maintenanceRun(
        connectionId,
        { database: db, ops: [op], tables: frag.map((t: any) => t.table) },
        (ev: any) => {
          if (ev.type === 'log') append(ev.message);
          else if (ev.type === 'row') append(`[${ev.op}] ${ev.table}: ${ev.ok ? 'ok' : 'FAIL'} — ${ev.message}`);
          else if (ev.type === 'done') append(`Done — ok: ${ev.ok ?? ''}, failed: ${ev.failed ?? ''}`);
          else if (ev.type === 'error') append(`ERROR: ${ev.message}`);
        },
      );
      notify('Defragmentation finished.', 'Tables');
      refresh();
    } catch (e) {
      append(`ERROR: ${(e as Error).message}`);
      notifyError(e, 'Tables');
    } finally {
      setOptimizing(false);
    }
  };

  const avail = data?.available !== false && !!data;
  const tables: any[] = data?.tables ?? [];
  const fragmented = tables.filter((t) => t.fragmented);

  return (
    <div className="space-y-3">
      <div className="flex items-end gap-2 flex-wrap">
        <label className="block text-xs">
          <span className="text-2xs text-nv-textSubtle block mb-0.5">Database</span>
          <select className="nv-select" value={db} onChange={(e) => setDb(e.target.value)}>
            <option value="">—</option>
            {databases.map((d) => <option key={d} value={d}>{d}</option>)}
          </select>
        </label>
        <button className="nv-btn text-xs" onClick={refresh} disabled={loading || !db}>
          {loading ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <RefreshCw size={12} className="inline mr-1" />}
          Refresh
        </button>
        <ExportButtons rows={tables} filenamePrefix={`dba-fragmentation-${db || connectionId}`} />
        <AiAnalysisButton
          connectionId={connectionId}
          kind="schema-advisor"
          params={{ database: db || undefined }}
          identifier={`fragmentation-${db || 'all'}`}
          database={db || undefined}
          engine={engine}
          title="Análisis con IA — Fragmentation"
          titleAttr="Analizar fragmentación de tablas con IA (plan de mantenimiento)"
        />
        {avail && fragmented.length > 0 && (
          <button className="nv-btn-primary text-xs" onClick={optimizeFragmented} disabled={optimizing || !db} title="Run maintenance on fragmented tables">
            {optimizing ? <Loader2 size={12} className="animate-spin inline mr-1" /> : <Play size={12} className="inline mr-1" />}
            {isPg ? 'VACUUM fragmented' : 'Optimize fragmented'} ({fragmented.length})
          </button>
        )}
      </div>

      {!avail && data?.message && <Callout tone="warn">{String(data.message)}</Callout>}
      {!avail && !data?.message && !db && <p className="text-2xs text-nv-textMuted">Select a database to inspect table fragmentation.</p>}

      {avail && (
        <div className="flex gap-2 flex-wrap">
          <SummaryPill label="Tables" value={data?.summary?.totalTables ?? 0} />
          <SummaryPill label="Fragmented" value={data?.summary?.fragmentedCount ?? 0} tone={(data?.summary?.fragmentedCount ?? 0) > 0 ? 'warn' : 'ok'} />
          <SummaryPill label="Reclaimable" value={bytes(data?.summary?.freeBytes ?? 0)} />
        </div>
      )}

      {avail && tables.length > 0 && (
        <div className="border border-nv-border rounded overflow-auto">
          <table className="w-full text-2xs">
            <thead className="bg-nv-gridHeader text-nv-textSubtle">
              <tr>
                <th className="text-left px-2 py-1">Table</th>
                <th className="text-left px-2 py-1">Engine</th>
                <th className="text-right px-2 py-1">Rows</th>
                <th className="text-right px-2 py-1">Data</th>
                <th className="text-right px-2 py-1">Index</th>
                <th className="text-right px-2 py-1">Free</th>
                <th className="text-right px-2 py-1">Free %</th>
                <th className="text-left px-2 py-1">Status</th>
                <th className="text-left px-2 py-1">PK</th>
              </tr>
            </thead>
            <tbody>
              {tables.map((t, i) => (
                <tr key={i} className="border-t border-nv-border">
                  <td className="px-2 py-1 font-mono">{t.schema ? `${t.schema}.` : ''}{t.table}</td>
                  <td className="px-2 py-1">{t.engine || '—'}</td>
                  <td className="px-2 py-1 text-right">{t.rows != null ? Number(t.rows).toLocaleString() : '—'}</td>
                  <td className="px-2 py-1 text-right">{bytes(t.dataBytes)}</td>
                  <td className="px-2 py-1 text-right">{bytes(t.indexBytes)}</td>
                  <td className="px-2 py-1 text-right">{bytes(t.freeBytes)}</td>
                  <td className="px-2 py-1 text-right">{t.freePct}%</td>
                  <td className="px-2 py-1">
                    {t.fragmented
                      ? <Pill tone="warn">fragmented</Pill>
                      : <Pill tone="ok">ok</Pill>}
                  </td>
                  <td className="px-2 py-1">
                    {t.hasPrimaryKey ? <CheckCircle2 size={11} className="text-nv-success" /> : <XCircle size={11} className="text-nv-danger" />}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      {avail && tables.length === 0 && !loading && (
        <p className="text-2xs text-nv-textMuted">No tables in {db}.</p>
      )}
      {log && (
        <div>
          <div className="text-2xs text-nv-textSubtle mb-0.5">Progress</div>
          <textarea readOnly className="w-full h-24 nv-input font-mono text-2xs bg-nv-bg" value={log} placeholder="Events from server…" />
        </div>
      )}
    </div>
  );
}

/* ───────────────────────── small UI helpers (extras) ───────────────────────── */

function SummaryPill({ label, value, tone = 'muted' }: { label: string; value: React.ReactNode; tone?: 'ok' | 'warn' | 'muted' }) {
  const cls = tone === 'ok' ? 'text-nv-success' : tone === 'warn' ? 'text-amber-500' : 'text-nv-textSubtle';
  return (
    <div className="px-2 py-1 rounded border border-nv-border bg-nv-bg text-2xs flex items-center gap-1.5">
      <span className="text-nv-textSubtle uppercase tracking-wide">{label}</span>
      <span className={`font-mono font-semibold ${cls}`}>{value}</span>
    </div>
  );
}

/* ───────────────────────── small UI helpers ───────────────────────── */

function Card({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <div className="border border-nv-border rounded bg-nv-toolbar/30">
      <div className="px-2 py-1 text-2xs font-semibold text-nv-accent border-b border-nv-border">{title}</div>
      <div className="p-2 text-xs space-y-1">{children}</div>
    </div>
  );
}

function KV({ label, value, ok }: { label: string; value: React.ReactNode; ok?: boolean }) {
  return (
    <div className="flex items-center gap-2">
      <span className="text-2xs text-nv-textSubtle w-32 shrink-0">{label}</span>
      <span className="font-mono text-2xs flex items-center gap-1">
        {ok === true && <CheckCircle2 size={11} className="text-nv-success" />}
        {ok === false && <XCircle size={11} className="text-nv-danger" />}
        {value}
      </span>
    </div>
  );
}

function Pill({ tone, children }: { tone: 'ok' | 'warn' | 'err' | 'muted'; children: React.ReactNode }) {
  const cls = {
    ok: 'bg-nv-success/20 text-nv-success',
    warn: 'bg-amber-500/20 text-amber-500',
    err: 'bg-nv-danger/20 text-nv-danger',
    muted: 'bg-nv-border text-nv-textSubtle',
  }[tone];
  return <span className={`px-1.5 py-0.5 rounded text-2xs font-mono ${cls}`}>{children}</span>;
}

function Callout({ tone, children }: { tone: 'info' | 'warn'; children: React.ReactNode }) {
  const cls = tone === 'warn' ? 'border-amber-500/40 bg-amber-500/10 text-amber-200' : 'border-nv-accent/40 bg-nv-accent/10 text-nv-text';
  const Icon = tone === 'warn' ? AlertTriangle : ShieldCheck;
  return (
    <div className={`border rounded p-2 text-2xs flex gap-2 ${cls}`}>
      <Icon size={13} className="shrink-0 mt-0.5" />
      <div>{children}</div>
    </div>
  );
}
